mapper.select:
select n.*, actor.name as actorName, case when n.target_type = 'article' then article.title when n.target_type = 'item' then items.name else '' end as targetTitle from `notification` n left join user actor on n.actor_id = actor.id left join article on n.target_type = 'article' and n.target_id = article.id left join items on n.target_type = 'item' and n.target_id = items.id
and n.user_id = #{userId} and n.is_read = #{isRead} and n.type = #{type}
order by n.id desc
